@import "@fontsource-variable/manrope/wght.css";

@custom-variant dark (&:where(.dark, .dark *));

:root {
  --background: #ffffff;
  --foreground: #0f172a;
  --surface: #ffffff;
  --border: #e2e8f0;
  --muted: #64748b;
  --primary-500-raw: oklch(0.563 0.241 260.8);
  --primary-950-raw: oklch(0.2 0.157 268.8);

  --shadow-sm-raw: 0 2px 4px 0 rgb(0 0 0 / 0.08), 0 1px 2px -1px rgb(0 0 0 / 0.06);
  --shadow-md-raw: 0 6px 12px -2px rgb(0 0 0 / 0.12), 0 3px 6px -3px rgb(0 0 0 / 0.08);
  --shadow-lg-raw: 0 12px 24px -4px rgb(0 0 0 / 0.16), 0 6px 12px -6px rgb(0 0 0 / 0.1);
}

.dark {
  --background: #0a0a0d;
  --foreground: #f8fafc;
  --surface: #18181c;
  --border: #27272e;
  --muted: #8a8a92;
  --shadow-sm-raw: 0 2px 6px 0 rgb(0 0 0 / 0.4), 0 0 0 1px rgb(255 255 255 / 0.06);
  --shadow-md-raw: 0 8px 16px -2px rgb(0 0 0 / 0.5), 0 0 0 1px rgb(255 255 255 / 0.08);
  --shadow-lg-raw: 0 16px 32px -4px rgb(0 0 0 / 0.6), 0 0 0 1px rgb(255 255 255 / 0.1);
}

/* Premium theme — graphite (near-neutral, slightly boosted for presence) primary, cognac as its own distinct secondary */

[data-theme="premium"] {
  --primary-500-raw: oklch(0.3 0.038 261.7);
  --primary-950-raw: oklch(0.09 0.044 265.7);

  --color-primary-50: oklch(0.97 0.017 261.7);
  --color-primary-100: oklch(0.93 0.019 261.7);
  --color-primary-200: oklch(0.86 0.024 261.7);
  --color-primary-300: oklch(0.73 0.029 261.7);
  --color-primary-400: oklch(0.52 0.033 261.7);
  --color-primary-600: oklch(0.26 0.039 262.6);
  --color-primary-700: oklch(0.21 0.041 263.5);
  --color-primary-800: oklch(0.165 0.042 264.4);
  --color-primary-900: oklch(0.125 0.043 265.3);

  --color-secondary-50: oklch(0.97 0.031 52.2);
  --color-secondary-100: oklch(0.93 0.041 52.2);
  --color-secondary-200: oklch(0.87 0.062 52.2);
  --color-secondary-300: oklch(0.715 0.083 52.2);
  --color-secondary-400: oklch(0.631 0.103 52.2);
  --color-secondary-500: oklch(0.589 0.124 52.2);
  --color-secondary-600: oklch(0.566 0.116 50.9);
  --color-secondary-700: oklch(0.519 0.107 49.5);
  --color-secondary-800: oklch(0.453 0.099 48.2);
  --color-secondary-900: oklch(0.375 0.091 46.9);
  --color-secondary-950: oklch(0.2 0.087 46.2);
}

/* Glass — independent layer, combines with any theme via data-glass + data-theme together */
[data-glass="regular"] {
  --glass-blur: 16px;
  --glass-saturate: 160%;
  --surface: rgb(255 255 255 / 0.65);
  --border: rgb(255 255 255 / 0.3);
  --shadow-lg-raw:
    0 12px 24px -4px rgb(0 0 0 / 0.12), inset 0 2px 0 0 rgb(255 255 255 / 0.9),
    inset 0 8px 16px -4px rgb(255 255 255 / 0.4), inset 0 0 0 1px rgb(255 255 255 / 0.3);
}

[data-glass="regular"].dark {
  --surface: rgb(255 255 255 / 0.08);
  --border: rgb(255 255 255 / 0.12);
  --shadow-lg-raw:
    0 16px 32px -4px rgb(0 0 0 / 0.6), inset 0 2px 0 0 rgb(255 255 255 / 0.5),
    inset 0 8px 16px -4px rgb(255 255 255 / 0.15), inset 0 0 0 1px rgb(255 255 255 / 0.12);
}

[data-glass="clear"] {
  --glass-blur: 8px;
  --glass-saturate: 130%;
  --surface: rgb(255 255 255 / 0.35);
  --border: rgb(255 255 255 / 0.2);
}

[data-glass="clear"].dark {
  --surface: rgb(255 255 255 / 0.04);
  --border: rgb(255 255 255 / 0.08);
}

@theme {
  /* Spacing */
  --spacing: 0.25rem;

  /* Semantic layer — Button consumes these, never raw palette values */
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-surface: var(--surface);
  --color-border: var(--border);
  --color-muted: var(--muted);

  /* Primary — Bold's electric blue by default; Premium theme overrides via [data-theme] above */
  --color-primary-50: oklch(0.97 0.036 260.8);
  --color-primary-100: oklch(0.93 0.059 260.8);
  --color-primary-200: oklch(0.87 0.104 260.8);
  --color-primary-300: oklch(0.701 0.15 260.8);
  --color-primary-400: oklch(0.609 0.195 260.8);
  --color-primary-500: var(--primary-500-raw);
  --color-primary-600: oklch(0.541 0.222 262.6);
  --color-primary-700: oklch(0.498 0.204 264.4);
  --color-primary-800: oklch(0.436 0.185 266.1);
  --color-primary-900: oklch(0.363 0.166 267.9);
  --color-primary-950: var(--primary-950-raw);

  /* Secondary — tangerine, shared brand accent across every theme */
  --color-secondary-50: oklch(0.97 0.04 45.1);
  --color-secondary-100: oklch(0.93 0.058 45.1);
  --color-secondary-200: oklch(0.87 0.093 45.1);
  --color-secondary-300: oklch(0.778 0.129 45.1);
  --color-secondary-400: oklch(0.727 0.164 45.1);
  --color-secondary-500: oklch(0.702 0.2 45.1);
  --color-secondary-600: oklch(0.672 0.187 43.8);
  --color-secondary-700: oklch(0.612 0.173 42.4);
  --color-secondary-800: oklch(0.526 0.16 41.1);
  --color-secondary-900: oklch(0.426 0.147 39.8);
  --color-secondary-950: oklch(0.2 0.14 39.1);

  /* Neutral — near-achromatic with a whisper of the primary hue */
  --color-neutral-50: oklch(0.985 0.002 280);
  --color-neutral-100: oklch(0.967 0.003 280);
  --color-neutral-200: oklch(0.92 0.004 280);
  --color-neutral-300: oklch(0.85 0.005 280);
  --color-neutral-400: oklch(0.65 0.006 280);
  --color-neutral-500: oklch(0.52 0.007 280);
  --color-neutral-600: oklch(0.42 0.007 280);
  --color-neutral-700: oklch(0.32 0.006 280);
  --color-neutral-800: oklch(0.22 0.005 280);
  --color-neutral-900: oklch(0.15 0.004 280);
  --color-neutral-950: oklch(0.09 0.003 280);

  /* Success — emerald, stays distinct from both new primaries */
  --color-success-100: oklch(0.93 0.05 165);
  --color-success-200: oklch(0.85 0.08 165);
  --color-success-500: oklch(0.55 0.14 165);
  --color-success-600: oklch(0.47 0.13 165);
  --color-success-700: oklch(0.39 0.11 165);
  --color-success-800: oklch(0.32 0.09 165);

  /* Warning — golden amber, stays distinct from tangerine secondary */
  --color-warning-100: oklch(0.94 0.05 85);
  --color-warning-200: oklch(0.88 0.09 85);
  --color-warning-500: oklch(0.78 0.16 85);
  --color-warning-600: oklch(0.68 0.16 83);
  --color-warning-700: oklch(0.57 0.14 81);
  --color-warning-800: oklch(0.46 0.12 79);

  --color-danger-100: oklch(0.93 0.06 25);
  --color-danger-200: oklch(0.85 0.11 25);
  --color-danger-500: oklch(0.6 0.21 25);
  --color-danger-600: oklch(0.52 0.2 25);
  --color-danger-700: oklch(0.44 0.18 25);
  --color-danger-800: oklch(0.36 0.15 25);

  /* Info — shifted from hue 240 to 195 (cyan/sky) so it stays visually distinct from the new primary blue at hue 260.8 */
  --color-info-100: oklch(0.93 0.04 195);
  --color-info-200: oklch(0.85 0.07 195);
  --color-info-500: oklch(0.62 0.15 195);
  --color-info-600: oklch(0.54 0.15 195);
  --color-info-700: oklch(0.46 0.14 195);
  --color-info-800: oklch(0.38 0.12 195);

  /* Radius — bumped up for the bubbly, chunky direction */
  --radius-sm: 8px;
  --radius-md: 12px;
  --radius-lg: 16px;
  --radius-xl: 20px;

  /* Shadows */
  --shadow-sm: var(--shadow-sm-raw);
  --shadow-md: var(--shadow-md-raw);
  --shadow-lg: var(--shadow-lg-raw);

  /* Typography */
  --font-sans: "Manrope Variable", ui-sans-serif, system-ui, -apple-system, sans-serif;

  /* Motion — consistent timing across every component */
  --duration-fast: 120ms;
  --duration-normal: 200ms;
  --duration-slow: 320ms;

  --ease-spring: linear(
    0,
    0.126 3.3%,
    0.378 6.7%,
    0.63 10%,
    0.826 13.3%,
    0.953 16.7%,
    1.02 20%,
    1.046 23.3%,
    1.047 26.7%,
    1.037 30%,
    1.025 33.3%,
    1.013 36.7%,
    1.005 40%,
    1.001 43.3%,
    0.998 46.7%,
    0.998 56.7%,
    0.999 60%,
    1 66.7%,
    1 100%
  );

  --ease-standard: cubic-bezier(0.4, 0, 0.2, 1);
  --ease-in: cubic-bezier(0.4, 0, 1, 1);
  --ease-out: cubic-bezier(0, 0, 0.2, 1);

  --animate-toast-progress: toast-progress linear forwards;

  @keyframes toast-progress {
    from {
      transform: scaleX(1);
    }
    to {
      transform: scaleX(0);
    }
  }

  @keyframes checkbox-pop {
    0% {
      transform: scale(1);
    }
    35% {
      transform: scale(1.25);
    }
    100% {
      transform: scale(1);
    }
  }
}
